// cdp_router — pair scraper HTTP responses to SKUs for sheet PROCESSADO updates.

const PROCESSING = '⏳ Processando';
const updatesByRow = {};

function responseAccepted(resp) {
  return Boolean(resp && (resp.accepted || resp.job_id || resp.body?.job_id));
}

function pushRowsForBatch(batch, updatesByRow) {
  const rows = Array.isArray(batch.sheet_rows) ? batch.sheet_rows : batch.items || [];
  for (const it of rows) {
    if (!it || !it.sku) continue;
    const rowNumber = it.row_number;
    if (rowNumber === undefined || rowNumber === null || rowNumber === '') continue;
    updatesByRow[rowNumber] = {
      PROCESSADO: PROCESSING,
      ENCONTRADO: PROCESSING,
      NOTIFICADO: PROCESSING,
    };
  }
}

function mergeWithSheetRows(updatesByRow) {
  let sheetItems = [];
  try {
    sheetItems = $('📊 Ler CDP_SKUs').all();
  } catch (e) {
    sheetItems = [];
  }
  if (!sheetItems.length) {
    return Object.entries(updatesByRow).map(([rowNumber, values]) => ({
      json: {
        row_number: Number(rowNumber),
        ...values,
      },
    }));
  }
  const merged = [];
  for (let i = 0; i < sheetItems.length; i++) {
    const item = sheetItems[i];
    const row = item.json || {};
    const rn = row.row_number;
    const upd = updatesByRow[rn];
    if (!upd) continue;
    merged.push({
      json: {
        ...row,
        PROCESSADO: upd.PROCESSADO,
        ENCONTRADO: upd.ENCONTRADO,
        NOTIFICADO: upd.NOTIFICADO,
      },
      pairedItem: item.pairedItem ?? { item: i },
    });
  }
  return merged;
}

const first = $input.first().json || {};
if (first.parallel_dispatch) {
  const responses = Array.isArray(first.scraper_responses) ? first.scraper_responses : [];
  const batches = Array.isArray(first.scraper_batches) ? first.scraper_batches : [];
  for (let i = 0; i < responses.length; i++) {
    const resp = responses[i];
    if (!responseAccepted(resp)) continue;
    const batch =
      batches.find((b) => Number(b.batch_index) === Number(resp.batch_index)) || batches[i];
    if (batch) pushRowsForBatch(batch, updatesByRow);
  }
  return mergeWithSheetRows(updatesByRow);
}

const httpItems = $input.all();
const batches = $('⚙️ Formatar Payload Scraper').all();

for (let i = 0; i < httpItems.length; i++) {
  const resp = httpItems[i].json;
  const hasJob = Boolean(resp.job_id);
  const sc = resp.statusCode != null ? Number(resp.statusCode) : hasJob ? 200 : 0;
  if (!hasJob && (sc < 200 || sc >= 300)) continue;
  const batch = batches[i]?.json;
  if (!batch) continue;
  pushRowsForBatch(batch, updatesByRow);
}
return mergeWithSheetRows(updatesByRow);

// cdp_router - format Scraper dispatch failures for Historico and optional email alert.

function env(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}

function workflowName() {
  try {
    if (typeof $workflow !== 'undefined' && $workflow && $workflow.name) {
      return String($workflow.name);
    }
  } catch (e) {}
  return '';
}

function isDevWorkflow() {
  return workflowName().trim().toLowerCase().startsWith('dev -');
}

function envFor(name) {
  if (isDevWorkflow() && name === 'NOTIFICATION_EMAIL_TO') {
    return env('CDP_DEV_NOTIFICATION_EMAIL_TO');
  }
  return env(name);
}

function compactError(resp) {
  const raw =
    resp.error ||
    resp.message ||
    resp.detail ||
    resp.body?.detail ||
    resp.body?.message ||
    resp.body?.error ||
    JSON.stringify(resp).substring(0, 500);
  return typeof raw === 'string' ? raw : JSON.stringify(raw);
}

function historicoFromError(item, resp, batch) {
  const nowIso = new Date().toISOString();
  const batchIndex = resp.batch_index || batch?.batch_index || 'unknown';
  const totalBatches = resp.total_batches || batch?.total_batches || 'unknown';
  const statusCode = resp.statusCode ?? resp.status_code ?? 'N/A';
  const errorMsg = compactError(resp);
  const items = Array.isArray(batch?.items) ? batch.items : Array.isArray(item.items) ? item.items : [];
  const batchSize = Number(resp.batch_size || batch?.batch_size || items.length || 0);
  const emailTo = String(
    item.reply_email || item.email_from || item.email || envFor('NOTIFICATION_EMAIL_TO') || ''
  ).trim();

  let html = '<h2>CDP Job Dispatcher - Scraper API Error</h2>';
  html += '<p><strong>Time:</strong> ' + nowIso + '</p>';
  html += '<p><strong>Batch:</strong> ' + batchIndex + ' / ' + totalBatches + '</p>';
  html += '<p><strong>HTTP Status:</strong> ' + statusCode + '</p>';
  html += '<p><strong>Error:</strong></p>';
  html += '<pre style="background:#fee2e2;padding:12px;border-radius:8px">' + errorMsg + '</pre>';
  html += '<p style="color:#718096;font-size:12px">Automated alert from CDP Job Dispatcher.</p>';

  return {
    job_id: String(resp.job_id || 'dispatch-scraper-batch-' + batchIndex),
    origem: 'dispatcher_error_scraper',
    solicitante: String(item.reply_email || item.email_from || item.chat_id || ''),
    disparado_em: String(resp.started_at || item.dispatched_at || nowIso),
    concluido_em: nowIso,
    tempo_segundos: '0',
    status: '❌ ERRO_DISPATCH',
    skus_lidos: String(batchSize),
    skus_validos: String(batchSize),
    skus_encontrados: '0',
    skus_falhos: String(batchSize),
    taxa_sucesso_sku: '0%',
    taxa_sucesso_sites: '0%',
    sites_pesquisados: String(Array.isArray(batch?.sites) ? batch.sites.length : 0),
    resumo_sites: '{}',
    lista_skus_csv: String(items.map((i) => i.sku).filter(Boolean).join(', ')),
    skus_repetidos: '—',
    job_error: '[HTTP ' + statusCode + '] ' + String(errorMsg).substring(0, 1000),
    email_from: emailTo,
    email_subject: 'Dispatcher Error - Scraper batch ' + batchIndex,
    email_html: html,
  };
}

const item = $input.first().json || {};

if (item.parallel_dispatch) {
  const responses = Array.isArray(item.scraper_responses) ? item.scraper_responses : [];
  const batches = Array.isArray(item.scraper_batches) ? item.scraper_batches : [];
  return responses
    .filter((resp) => !resp.accepted)
    .map((resp, index) => {
      const batch =
        batches.find((b) => Number(b.batch_index) === Number(resp.batch_index)) || batches[index] || {};
      return { json: historicoFromError(item, resp, batch) };
    });
}

return [{ json: historicoFromError(item, item, item) }];

// cdp_router — pass SKUs through; optional random sample via CDP_DISPATCH_SAMPLE_SIZE (0 = all).

function env(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}
function envInt(name, defaultVal) {
  const raw = env(name);
  if (!raw) return defaultVal;
  const n = parseInt(raw, 10);
  return Number.isFinite(n) && n >= 0 ? n : defaultVal;
}

const data = $input.first().json;
const all = Array.isArray(data.skus) ? data.skus : [];
const allSheetRows = Array.isArray(data.sheet_rows) ? data.sheet_rows : all;
const maxSkus = envInt('CDP_DISPATCH_SAMPLE_SIZE', 0);
let skus = all;
let sampled = false;
if (maxSkus > 0 && all.length > maxSkus) {
  const copy = [...all];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    const tmp = copy[i];
    copy[i] = copy[j];
    copy[j] = tmp;
  }
  skus = copy.slice(0, maxSkus);
  sampled = true;
}
const sampledSkuSet = new Set(
  skus.map((row) => String(row?.sku || row?.SKU || row).trim().toUpperCase()).filter(Boolean)
);
const sheetRows = allSheetRows.filter((row) => {
  const sku = String(row?.sku || row?.SKU || row).trim().toUpperCase();
  return sampledSkuSet.has(sku);
});

const batchGroupId = 'bg-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 8);
try {
  if (typeof $getWorkflowStaticData === 'function') {
    const sd = $getWorkflowStaticData('global');
    sd.cdp_last_batch_group_id = batchGroupId;
  }
} catch (e) {}

let commandRoute = 'analisar';
try {
  const tg = $('🔀 Switch Comando (Telegram)').first().json;
  if (tg && tg.route) commandRoute = String(tg.route);
} catch (e) {}
if (commandRoute === 'analisar') {
  try {
    const em = $('🔀 Switch Comando (Email)').first().json;
    if (em && em.route) commandRoute = String(em.route);
  } catch (e) {}
}

return [
  {
    json: {
      ...data,
      skus,
      sheet_rows: sheetRows,
      valid_skus: skus.length,
      input_valid_skus: sheetRows.length,
      dispatch_sampled: sampled,
      dispatch_sample_limit: maxSkus,
      dispatch_total_before_sample: all.length,
      dispatch_sheet_rows_before_sample: allSheetRows.length,
      batch_group_id: batchGroupId,
      command_route: commandRoute,
    },
  },
];

// cdp_router — Scraper POST /api/v1/jobs (force_refresh=false → Redis/PostgreSQL 24h cache).

const DEFAULT_BATCH_SIZE = 100;
const MAX_BATCH_SIZE = 100;
const DEFAULT_SITES = [
  'gm',
  'ml',
  'vw',
  'eu',
];
const DEFAULT_SCRAPER_API_BASE =
  'https://cdp-scrapers-api-prod.bravecoast-b14d791e.eastus2.azurecontainerapps.io';
const DEFAULT_N8N_WEBHOOK_BASE = 'https://automacao.tktechnologies.com.br';
const data = $input.first().json;
const skus = Array.isArray(data.skus) ? data.skus : [];
const sheetRows = Array.isArray(data.sheet_rows) ? data.sheet_rows : skus;

function env(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}
function workflowName() {
  try {
    if (typeof $workflow !== 'undefined' && $workflow && $workflow.name) {
      return String($workflow.name).trim();
    }
  } catch (e) {}
  return '';
}
function isDevWorkflow() {
  return /^DEV\s*-/i.test(workflowName());
}
function devEnvName(name) {
  const map = {
    CDP_SCRAPER_API_BASE: 'CDP_DEV_SCRAPER_API_BASE',
    MUVSTOK_SCRAPER_API_BASE: 'CDP_DEV_SCRAPER_API_BASE',
    CDP_API_KEY: 'CDP_DEV_API_KEY',
    MUVSTOK_API_KEY: 'CDP_DEV_API_KEY',
    API_KEY: 'CDP_DEV_API_KEY',
    CDP_SCRAPER_BATCH_SIZE: 'CDP_DEV_SCRAPER_BATCH_SIZE',
    CDP_SCRAPER_SITES: 'CDP_DEV_SCRAPER_SITES',
    WEBHOOK_URL: 'CDP_DEV_WEBHOOK_URL',
    CDP_N8N_WEBHOOK_URL: 'CDP_DEV_N8N_WEBHOOK_URL',
    CDP_N8N_WEBHOOK_PATH: 'CDP_DEV_N8N_WEBHOOK_PATH',
  };
  return map[name] || '';
}
function envFor(name) {
  if (!isDevWorkflow()) return env(name);
  const mapped = devEnvName(name);
  const value = mapped ? env(mapped) : '';
  if (value) return value;
  if (name === 'WEBHOOK_URL') return env('WEBHOOK_URL') || DEFAULT_N8N_WEBHOOK_BASE;
  if (name === 'CDP_N8N_WEBHOOK_PATH') return 'webhook/dev-scraper-result';
  return '';
}
function envList(name) {
  const raw = envFor(name);
  return raw ? raw.split(',').map((s) => s.trim()).filter(Boolean) : [];
}
function trimTrailingSlashes(value) {
  let out = String(value || '').trim();
  while (out.endsWith('/')) out = out.slice(0, -1);
  return out;
}
function trimSlashes(value) {
  let out = String(value || '').trim();
  while (out.startsWith('/')) out = out.slice(1);
  while (out.endsWith('/')) out = out.slice(0, -1);
  return out;
}
function readStaticRequester() {
  try {
    if (typeof $getWorkflowStaticData === 'function') {
      const sd = $getWorkflowStaticData('global');
      if (sd && sd.cdp_sheet_requester) return sd.cdp_sheet_requester;
    }
  } catch (e) {}
  return null;
}
function looksLikeEmail(value) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(value || '').trim());
}
function skuKey(value) {
  return String(value || '')
    .trim()
    .toUpperCase()
    .replace(/[\s\-\.\\/]/g, '');
}

const configuredSites = envList('CDP_SCRAPER_SITES');
const sites = configuredSites.length ? configuredSites : DEFAULT_SITES;
const commandRoute = String(data.command_route || 'analisar');
const scraperApiBase = trimTrailingSlashes(
  envFor('CDP_SCRAPER_API_BASE') ||
    envFor('MUVSTOK_SCRAPER_API_BASE') ||
    (isDevWorkflow() ? '' : DEFAULT_SCRAPER_API_BASE)
);
const apiKey = envFor('CDP_API_KEY') || envFor('MUVSTOK_API_KEY') || envFor('API_KEY');
const batchSizeRaw = Number(envFor('CDP_SCRAPER_BATCH_SIZE') || DEFAULT_BATCH_SIZE);
const BATCH_SIZE = Math.max(
  1,
  Math.min(MAX_BATCH_SIZE, Number.isFinite(batchSizeRaw) ? batchSizeRaw : DEFAULT_BATCH_SIZE)
);

const ctx = readStaticRequester();
let chatId = String(data.telegram_chat_id || data.chat_id || '').trim();
let emailFrom = String(data.email_from || '').trim();
const notifyRaw = String(data.notify || '').trim();
let commandOrigin = String(data.command_origin || data.origem || '').trim().toLowerCase();
let replyChannel = String(data.reply_channel || '').trim().toLowerCase();
if (!emailFrom && looksLikeEmail(notifyRaw)) emailFrom = notifyRaw;
const dataHasChannel = Boolean(
  replyChannel || commandOrigin === 'email' || commandOrigin === 'telegram' || emailFrom || chatId
);
if (ctx) {
  if (!dataHasChannel && !replyChannel && ctx.reply_channel) {
    replyChannel = String(ctx.reply_channel).trim().toLowerCase();
  }
  if (!dataHasChannel && !commandOrigin && ctx.command_origin) {
    commandOrigin = String(ctx.command_origin).trim().toLowerCase();
  }
  if (!dataHasChannel && !emailFrom && ctx.email_from) emailFrom = String(ctx.email_from).trim();
  const inputIsEmail = commandOrigin === 'email' || replyChannel === 'email' || emailFrom;
  if (!inputIsEmail && !chatId && ctx.chat_id) chatId = String(ctx.chat_id).trim();
}
let notify = 'none';
if (!replyChannel) {
  if (commandOrigin === 'email' || emailFrom) replyChannel = 'email';
  else if (commandOrigin === 'telegram' || chatId) replyChannel = 'telegram';
}
if (!commandOrigin && replyChannel) commandOrigin = replyChannel;
if (replyChannel === 'email') {
  notify = 'email';
  commandOrigin = 'email';
  chatId = '';
} else if (replyChannel === 'telegram') {
  notify = 'telegram';
  commandOrigin = 'telegram';
  emailFrom = '';
} else if (chatId) {
  notify = 'telegram';
  replyChannel = 'telegram';
  commandOrigin = commandOrigin || 'telegram';
} else if (emailFrom) {
  notify = 'email';
  replyChannel = 'email';
  commandOrigin = commandOrigin || 'email';
}

const batchGroupId =
  String(data.batch_group_id || '').trim() ||
  'bg-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 8);
const adHoc = String(commandRoute || '').startsWith('sku');

let callbackUrl = envFor('CDP_N8N_WEBHOOK_URL');
if (!callbackUrl) {
  const base = trimTrailingSlashes(envFor('WEBHOOK_URL'));
  const rel = trimSlashes(envFor('CDP_N8N_WEBHOOK_PATH') || 'webhook/scraper-result');
  if (base) callbackUrl = base + '/' + rel;
}
if (!callbackUrl && !isDevWorkflow()) {
  callbackUrl = 'https://automacao.tktechnologies.com.br/webhook/scraper-result';
}

function encodeQueryParam(key, value) {
  return encodeURIComponent(key) + '=' + encodeURIComponent(String(value));
}
function buildQueryString(parts) {
  return parts.map(([k, v]) => encodeQueryParam(k, v)).join('&');
}
const deliveryMode = notify === 'none' ? 'legacy' : 'aggregate';
const queryParts = [
  ['notify', notify],
  ['reply_channel', replyChannel || notify],
  ['command_origin', commandOrigin || replyChannel || notify],
  ['batch_group_id', batchGroupId],
  ['dual_run', 'scraper'],
  ['command_route', commandRoute],
  ['delivery_mode', deliveryMode],
];
if (notify === 'telegram' && chatId) queryParts.push(['chat_id', chatId]);
if (notify === 'email' && emailFrom) queryParts.push(['reply_email', emailFrom]);
if (adHoc) queryParts.push(['ad_hoc', 'true']);
callbackUrl += (callbackUrl.includes('?') ? '&' : '?') + buildQueryString(queryParts);

const batches = [];
for (let i = 0; i < skus.length; i += BATCH_SIZE) {
  batches.push(skus.slice(i, i + BATCH_SIZE));
}
const totalBatches = batches.length;

return batches.map((batch, index) => {
  const batchSkuKeys = new Set(batch.map((it) => skuKey(it.sku)));
  const batchSheetRows = sheetRows.filter((it) => batchSkuKeys.has(skuKey(it.sku || it.SKU || it)));
  return {
    json: {
      callback_url: callbackUrl,
      items: batch.map((it) => ({
        sku: it.sku,
        brand: it.brand || '',
        description: it.description || '',
      })),
      sheet_rows: batchSheetRows.map((it) => ({
        sku: it.sku,
        row_number: it.row_number ?? null,
      })),
      sites,
      priority: 5,
      force_refresh: false,
      api_jobs_url: scraperApiBase + '/api/v1/jobs',
      api_key: apiKey,
      batch_group_id: batchGroupId,
      batch_index: index + 1,
      total_batches: totalBatches,
      batch_size: batch.length,
      sheet_row_count: batchSheetRows.length,
      ad_hoc: adHoc,
      notify,
      reply_channel: replyChannel || notify,
      command_origin: commandOrigin || replyChannel || notify,
      chat_id: notify === 'telegram' ? chatId : undefined,
      reply_email: notify === 'email' ? emailFrom : '',
      command_route: commandRoute,
      metadata: {
        source: 'cdp_router',
        pipeline: 'scraper',
        command_route: commandRoute,
        command_origin: commandOrigin || replyChannel || notify,
        reply_channel: replyChannel || notify,
        notify,
        delivery_mode: deliveryMode,
        chat_id: notify === 'telegram' ? chatId : '',
        reply_email: notify === 'email' ? emailFrom : '',
        batch_group_id: batchGroupId,
        batch_index: index + 1,
        total_batches: totalBatches,
        cache_policy: 'redis_24h',
        unique_skus: batch.length,
        sheet_rows: batchSheetRows.length,
      },
    },
  };
});

// cdp_router — validate sheet rows, dedupe dispatch SKUs, preserve sheet rows.

const raw = $input.all();
const seen = new Set();
const uniqueBySku = new Map();
const sheetRows = [];
const dqIssues = [];
let skippedProcessado = 0;

function normalizeStatus(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function normalizeSku(value) {
  return String(value || '')
    .trim()
    .toUpperCase()
    .replace(/[\s\-\.\\/]/g, '');
}

function pickSheetField(row, base) {
  if (!row || typeof row !== 'object') return '';
  const robot = base + ' 🤖';
  for (const k of [base, robot]) {
    const v = row[k];
    if (v !== null && v !== undefined && String(v).trim() !== '') return v;
  }
  return row[base] ?? row[robot] ?? '';
}

for (const item of raw) {
  const row = item.json;
  const rawSku = row.CODIGO ?? row.SKU ?? row.sku ?? row.codigo;
  const sku = normalizeSku(rawSku);

  const processado = normalizeStatus(pickSheetField(row, 'PROCESSADO'));
  if (processado === 'processado' || processado === 'sim' || processado === 'true') {
    skippedProcessado++;
    continue;
  }

  if (!sku) {
    dqIssues.push({ issue: 'EMPTY_SKU', row: JSON.stringify(row) });
    continue;
  }
  if (sku.length < 3) {
    dqIssues.push({ issue: 'SHORT_SKU', sku });
    continue;
  }
  if (seen.has(sku)) {
    dqIssues.push({
      issue: 'DUPLICATE_SKU',
      sku,
      row_number: row.row_number ?? null,
      action: 'deduped_dispatch_preserved_sheet_row',
    });
  }
  seen.add(sku);

  const rowData = {
    sku,
    sku_original: rawSku ? String(rawSku).trim() : '',
    brand: row.UNIDADE ? String(row.UNIDADE).trim() : '',
    description: row.ITEM ? String(row.ITEM).trim() : '',
    row_number: row.row_number ?? null,
    notify_email: row['E-MAIL'] ? String(row['E-MAIL']).trim() : '',
    notify_phone: row.CONTATO ? String(row.CONTATO).trim() : '',
  };
  sheetRows.push(rowData);

  if (!uniqueBySku.has(sku)) {
    uniqueBySku.set(sku, { ...rowData });
  } else {
    const existing = uniqueBySku.get(sku);
    if (existing) {
      if (!existing.brand && rowData.brand) existing.brand = rowData.brand;
      if (!existing.description && rowData.description) existing.description = rowData.description;
      if (!existing.notify_email && rowData.notify_email) existing.notify_email = rowData.notify_email;
      if (!existing.notify_phone && rowData.notify_phone) existing.notify_phone = rowData.notify_phone;
    }
  }
}

const duplicateIssues = dqIssues.filter((i) => i.issue === 'DUPLICATE_SKU');
const duplicateSkus = [...new Set(duplicateIssues.map((i) => i.sku).filter(Boolean))];
const skus = [...uniqueBySku.values()];

return [
  {
    json: {
      total_read: raw.length,
      input_valid_skus: sheetRows.length,
      valid_skus: skus.length,
      unique_skus: seen.size,
      skipped_processado: skippedProcessado,
      duplicates: duplicateIssues.length,
      duplicate_skus: duplicateSkus,
      empty_skus: dqIssues.filter((i) => i.issue === 'EMPTY_SKU').length,
      short_skus: dqIssues.filter((i) => i.issue === 'SHORT_SKU').length,
      dq_issues: dqIssues,
      skus,
      sheet_rows: sheetRows,
      dispatched_at: new Date().toISOString(),
    },
  },
];

// ─── Telegram Command Router v4 — adds .status / .andamento ─────────────────

const DEFAULT_SCRAPER_API_BASE =
  'https://cdp-scrapers-api-prod.bravecoast-b14d791e.eastus2.azurecontainerapps.io';

function envValue(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {
    return '';
  }
  try {
