const subject = String(msg.subject || '').trim();
const bodyRaw = String(msg.textPlain || msg.text || msg.html || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

const subjectL = subject.toLowerCase();
const bodyLines = bodyRaw.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
const bodyFirstL = (bodyLines[0] || '').toLowerCase();
let cmdSource;
if (subjectL.startsWith('.analisar') || subjectL.startsWith('.sku')) {
  cmdSource = subject;
