  const parts = msg.payload.parts;
  // Flatten: some emails nest parts inside parts (multipart/mixed > multipart/alternative + attachment)
  const allParts = [];
  function collectParts(partsList) {
    for (const p of partsList) {
      allParts.push(p);
      if (p.parts) collectParts(p.parts);
    }
  }
  collectParts(parts);

  for (const part of allParts) {
    const fn = String(part.filename || '').trim();
    if (/\.(xlsx?|csv)$/i.test(fn) && part.body && part.body.attachmentId) {
      xlsAttachment = {
        id: part.body.attachmentId,
        name: fn,
        mimeType: part.mimeType || '',
        size: part.body.size || 0
      };
      break;
    }
  }
  // Also try to get messageId from raw payload
  if (!messageId && msg.payload.headers) {
    const msgIdHeader = msg.payload.headers.find(h => h.name?.toLowerCase() === 'message-id');
    if (msgIdHeader) messageId = String(msgIdHeader.value || '').trim();
