    .filter(Boolean);
  scraperJobIds = [...new Set(mergedScraperIds)];
  stokapiJobId = stokapiJobId || String(previousRun.stokapi_job_id || '').trim();
}

if (!scraperJobIds.length && !stokapiJobId) {
  return [];
}

const activeRun = {
  batch_group_id: batchGroupId,
  scraper_job_ids: scraperJobIds,
  stokapi_job_id: stokapiJobId,
  total_skus: totalSkus,
  dispatched_at: previousRun?.batch_group_id === batchGroupId ? previousRun.dispatched_at || dispatchedAt : dispatchedAt,
  estimated_seconds: estimatedSeconds,
  chat_id: chatId,
  reply_channel: replyChannel || (replyEmail ? 'email' : chatId ? 'telegram' : ''),
  reply_email: replyEmail,
  command_origin: commandOrigin,
  command_route: commandRoute,
  progress_enabled: progressEnabled,
  delivery_mode: deliveryMode,
  sheet_row_numbers: sheetRowNumbers,
  scraper_completed: scraperJobIds.length < 1,
  stokapi_completed: !stokapiJobId,
  last_progress_notified_pct: 0,
  progress_message_count: 0,
};

try {
  if (typeof $getWorkflowStaticData === 'function') {
    const sd = $getWorkflowStaticData('global');
    sd.cdp_active_run = activeRun;
  }
} catch (e) {}

const apiBase = trimTrailingSlashes(
  envFor('CDP_SCRAPER_API_BASE') ||
    envFor('MUVSTOK_SCRAPER_API_BASE') ||
    (isDevWorkflow() ? '' : DEFAULT_SCRAPER_API_BASE)
);
const apiKey = envFor('CDP_API_KEY') || envFor('MUVSTOK_API_KEY') || envFor('API_KEY');

return [
  {
    json: {
      registered: true,
      ...activeRun,
      dispatch_runs_url: apiBase ? apiBase + '/api/v1/dispatch-runs' : '',
      dispatch_runs_api_key: apiKey,
      reply_channel: replyChannel || (replyEmail ? 'email' : chatId ? 'telegram' : ''),
      reply_email: replyEmail,
      command_origin: commandOrigin,
      progress_enabled: progressEnabled,
      delivery_mode: deliveryMode,
      sheet_row_numbers: sheetRowNumbers,
    },
  },
];

// cdp_router — .status / .andamento: resolve active run and API poll targets.

const DEFAULT_SCRAPER_API_BASE =
  'https://cdp-scrapers-api-prod.bravecoast-b14d791e.eastus2.azurecontainerapps.io';

function env(name) {
  try {
    if (typeof $env !== 'undefined' && $env && $env[name]) {
      return String($env[name]).trim();
    }
  } catch (e) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) {
      return String(process.env[name]).trim();
    }
  } catch (e) {}
  return '';
}
function workflowName() {
  try {
    if (typeof $workflow !== 'undefined' && $workflow && $workflow.name) {
      return String($workflow.name).trim();
    }
  } catch (e) {}
  return '';
}
function isDevWorkflow() {
  return /^DEV\s*-/i.test(workflowName());
}
function devEnvName(name) {
  const map = {
    CDP_SCRAPER_API_BASE: 'CDP_DEV_SCRAPER_API_BASE',
    MUVSTOK_SCRAPER_API_BASE: 'CDP_DEV_SCRAPER_API_BASE',
    CDP_MUVSTOK_API_BASE: 'CDP_DEV_MUVSTOK_API_BASE',
    CDP_API_KEY: 'CDP_DEV_API_KEY',
    MUVSTOK_API_KEY: 'CDP_DEV_API_KEY',
    API_KEY: 'CDP_DEV_API_KEY',
    CDP_MUVSTOK_API_KEY: 'CDP_DEV_MUVSTOK_API_KEY',
  };
  return map[name] || '';
}
function envFor(name) {
  if (!isDevWorkflow()) return env(name);
  const mapped = devEnvName(name);
  return mapped ? env(mapped) : '';
}

function trimTrailingSlashes(value) {
  let out = String(value || '').trim();
  while (out.endsWith('/')) out = out.slice(0, -1);
  return out;
}

const router = $input.first().json;
const chatId = String(router.chat_id || router.notify || '').trim();

let run = null;
try {
  if (typeof $getWorkflowStaticData === 'function') {
    run = $getWorkflowStaticData('global').cdp_active_run || null;
  }
} catch (e) {}

if (!run || !run.batch_group_id) {
  try {
    const apiRun = $('📊 GET dispatch run (chat)').first().json;
    if (apiRun && apiRun.batch_group_id) {
      run = {
        batch_group_id: apiRun.batch_group_id,
        scraper_job_ids: apiRun.scraper_job_ids || [],
        stokapi_job_id: apiRun.stokapi_job_id || '',
        total_skus: Number(apiRun.total_skus || 0),
        dispatched_at: apiRun.dispatched_at,
        estimated_seconds: Number(apiRun.estimated_seconds || 0),
        chat_id: apiRun.chat_id,
      };
    }
  } catch (e) {}
}

const TTL_HOURS = 24;
if (run && run.dispatched_at) {
  const ageMs = Date.now() - new Date(run.dispatched_at).getTime();
  if (ageMs > TTL_HOURS * 60 * 60 * 1000) {
    run = null;
  }
}

if (!run || !run.batch_group_id) {
  return [
    {
      json: {
        skip_poll: true,
        chat_id: chatId,
        msg_telegram:
          '🤖 *Assistente CDP*\n\nNenhuma consulta em andamento.\nUse `.analisar` ou `.sku` para iniciar.',
      },
    },
  ];
}

if (chatId && run.chat_id && chatId !== String(run.chat_id).trim()) {
  return [
    {
      json: {
        skip_poll: true,
        chat_id: chatId,
        msg_telegram:
          '🤖 *Assistente CDP*\n\nNão há consulta ativa para este chat.\nUse `.analisar` ou `.sku` para iniciar.',
      },
    },
  ];
}

const scraperBase = trimTrailingSlashes(
  envFor('CDP_SCRAPER_API_BASE') ||
    envFor('MUVSTOK_SCRAPER_API_BASE') ||
    (isDevWorkflow() ? '' : DEFAULT_SCRAPER_API_BASE)
);
const stokapiBase = trimTrailingSlashes(
  envFor('CDP_MUVSTOK_API_BASE') ||
    (isDevWorkflow() ? '' : 'https://cdp-muv-api.bravecoast-b14d791e.eastus2.azurecontainerapps.io')
);
const apiKey = envFor('CDP_API_KEY') || envFor('MUVSTOK_API_KEY') || envFor('API_KEY');
const stokapiKey = envFor('CDP_MUVSTOK_API_KEY') || apiKey;

const scraperJobIds = Array.isArray(run.scraper_job_ids) ? run.scraper_job_ids : [];
const primaryScraperJobId = scraperJobIds[0] || '';

return [
  {
    json: {
      skip_poll: false,
      chat_id: chatId || run.chat_id,
      batch_group_id: run.batch_group_id,
      total_skus: Number(run.total_skus || 0),
      dispatched_at: run.dispatched_at,
      estimated_seconds: Number(run.estimated_seconds || 0),
      scraper_job_ids: scraperJobIds,
      stokapi_job_id: String(run.stokapi_job_id || ''),
      scraper_job_url: primaryScraperJobId
        ? scraperBase + '/api/v1/jobs/' + primaryScraperJobId
        : '',
      stokapi_job_url: run.stokapi_job_id
        ? stokapiBase + '/api/v1/muvstok/jobs/' + run.stokapi_job_id
        : '',
      scraper_api_key: apiKey,
      stokapi_api_key: stokapiKey,
    },
  },
];

// cdp_router — format combined scraper + StokAPI progress for Telegram.

function num(v, fallback) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function statusLabel(status) {
  const s = String(status || '').toLowerCase();
  if (s === 'completed' || s === 'succeeded') return 'concluído';
  if (s === 'partial' || s === 'partially_succeeded') return 'parcial';
  if (s === 'failed') return 'falhou';
  if (s === 'running' || s === 'processing') return 'em execução';
  if (s === 'pending' || s === 'queued') return 'na fila';
  return s || 'desconhecido';
}

function formatDuration(seconds) {
  const sec = Math.max(0, Math.round(num(seconds, 0)));
  if (sec < 60) return '~' + sec + ' s';
  const mins = Math.ceil(sec / 60);
  return mins === 1 ? '~1 minuto' : '~' + mins + ' minutos';
}

function formatClock(iso) {
  if (!iso) return '—';
  try {
    const d = new Date(iso);
    return d.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
  } catch (e) {
    return '—';
  }
}

const prep = $('📊 Status: preparar').first().json;
if (prep.skip_poll) {
  return [{ json: { chat_id: prep.chat_id, msg_telegram: prep.msg_telegram } }];
}

let scraper = {};
let stokapi = {};
try {
  scraper = $('📊 GET Scraper Job').first().json;
} catch (e) {}
try {
  stokapi = $('📊 GET StokAPI Job').first().json;
} catch (e) {}

const total = num(prep.total_skus, num(scraper.total_items, num(stokapi.submitted_sku_count, 0)));
const scraperProcessed = num(
  scraper.items_processed,
  num(scraper.items_succeeded, 0) + num(scraper.items_failed, 0)
);
const scraperPct = num(scraper.progress_pct, total > 0 ? (scraperProcessed / total) * 100 : 0);
const stokProcessed = num(
  stokapi.processed_sku_count,
  num(stokapi.succeeded_sku_count, 0) + num(stokapi.failed_sku_count, 0)
);
const stokPct = num(stokapi.progress_pct, total > 0 ? (stokProcessed / total) * 100 : 0);

const dispatchedAt = prep.dispatched_at || scraper.started_at;
const elapsedSec = dispatchedAt
  ? Math.max(0, Math.floor((Date.now() - new Date(dispatchedAt).getTime()) / 1000))
  : 0;

const scraperEta = scraper.estimated_seconds_remaining;
const stokEta = stokapi.estimated_seconds_remaining;
const etaSec =
  num(scraperEta, null) != null && scraperEta > 0
    ? scraperEta
    : num(stokEta, null) != null && stokEta > 0
      ? stokEta
      : Math.max(0, num(prep.estimated_seconds, 0) - elapsedSec);

const lines = [
  '🤖 *Assistente CDP* — andamento',
  '',
  '📦 *Sites (scraper):* ' +
    scraperProcessed +
    '/' +
    (total || '?') +
    ' peças (~' +
    Math.round(scraperPct) +
    '%) — ' +
    statusLabel(scraper.status),
];

if (etaSec > 0 && String(scraper.status || '').toLowerCase() === 'running') {
  lines.push('⏱️ ' + formatDuration(etaSec) + ' restantes (estimativa)');
}
lines.push(
  '🕐 Início: ' + formatClock(dispatchedAt) + ' · Já decorrido: ' + formatDuration(elapsedSec)
);
lines.push('');
lines.push(
  '📦 *Estoque:* ' +
    statusLabel(stokapi.status) +
    ' (' +
    stokProcessed +
    '/' +
    (total || '?') +
    ' com dados, ~' +
    Math.round(stokPct) +
    '%)'
);

const scraperTerminal = ['completed', 'partial', 'failed'].includes(
  String(scraper.status || '').toLowerCase()
);
const stokTerminal = ['succeeded', 'partially_succeeded', 'failed'].includes(
  String(stokapi.status || '').toLowerCase()
);

try {
  if (typeof $getWorkflowStaticData === 'function') {
    const sd = $getWorkflowStaticData('global');
    if (sd.cdp_active_run) {
      sd.cdp_active_run.scraper_completed = scraperTerminal;
      sd.cdp_active_run.stokapi_completed = stokTerminal;
      if (scraperTerminal && stokTerminal) {
        delete sd.cdp_active_run;
      }
    }
  }
} catch (e) {}

return [{ json: { chat_id: prep.chat_id, msg_telegram: lines.join('\n') } }];
